var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents()
    .AddAuthenticationStateSerialization(options => options.SerializeAllClaims = true);

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<IdentityRedirectManager>();

builder.Services.AddAuthentication(options =>
    {
        options.DefaultScheme = IdentityConstants.ApplicationScheme;
        options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
    })
    .AddIdentityCookies();
builder.Services.AddAuthorization();

var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlite(connectionString));
builder.Services.AddDatabaseDeveloperPageExceptionFilter();

builder.Services.AddIdentityCore<ApplicationUser>(options =>
    {
        options.SignIn.RequireConfirmedAccount = true;
        options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
    })
    .AddRoles<IdentityRole>()
    .AddEntityFrameworkStores<ApplicationDbContext>()
    .AddSignInManager()
    .AddDefaultTokenProviders();

builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();

// Register HttpClient for server-side prerendering of WASM components
builder.Services.AddScoped(sp =>
{
    var navigationManager = sp.GetRequiredService<NavigationManager>();
    return new HttpClient { BaseAddress = new Uri(navigationManager.BaseUri) };
});

var app = builder.Build();

// Seed roles and sample data
using (var scope = app.Services.CreateScope())
{
    var services = scope.ServiceProvider;
    var db = services.GetRequiredService<ApplicationDbContext>();

    if (app.Environment.IsDevelopment())
    {
        await db.Database.MigrateAsync();
    }

    var roleManager = services.GetRequiredService<RoleManager<IdentityRole>>();
    if (!await roleManager.RoleExistsAsync("Dispatcher"))
    {
        await roleManager.CreateAsync(new IdentityRole("Dispatcher"));
    }

    if (!db.Shipments.Any())
    {
        db.Shipments.AddRange(
            new Shipment
            {
                TrackingNumber = "SHP-DEMO0001",
                Origin = "New York, NY",
                Destination = "Los Angeles, CA",
                Status = "InTransit",
                CreatedAt = DateTime.UtcNow.AddDays(-3),
                EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                CustomerEmail = "customer@example.com",
                Notes = "Fragile items"
            },
            new Shipment
            {
                TrackingNumber = "SHP-DEMO0002",
                Origin = "Chicago, IL",
                Destination = "Houston, TX",
                Status = "Pending",
                CreatedAt = DateTime.UtcNow.AddDays(-1),
                EstimatedDelivery = DateTime.UtcNow.AddDays(5),
                CustomerEmail = "customer@example.com"
            },
            new Shipment
            {
                TrackingNumber = "SHP-DEMO0003",
                Origin = "Seattle, WA",
                Destination = "Miami, FL",
                Status = "Delivered",
                CreatedAt = DateTime.UtcNow.AddDays(-7),
                EstimatedDelivery = DateTime.UtcNow.AddDays(-1),
                CustomerEmail = "another@example.com",
                Notes = "Delivered to front desk"
            }
        );
        await db.SaveChangesAsync();
    }
}

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
    app.UseMigrationsEndPoint();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

// API Endpoints
var api = app.MapGroup("/api/shipments");

string GenerateTrackingNumber()
{
    const string chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    var random = new Random();
    var code = new string(Enumerable.Range(0, 8).Select(_ => chars[random.Next(chars.Length)]).ToArray());
    return $"SHP-{code}";
}

// GET all shipments (Dispatcher only)
api.MapGet("/", async (ApplicationDbContext db, string? status) =>
{
    var query = db.Shipments.AsQueryable();
    if (!string.IsNullOrEmpty(status))
    {
        query = query.Where(s => s.Status == status);
    }
    var shipments = await query.OrderByDescending(s => s.CreatedAt).ToListAsync();
    return Results.Ok(shipments.Select(s => new ShipmentDto
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = Enum.Parse<ShipmentStatus>(s.Status),
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    }));
}).RequireAuthorization(p => p.RequireRole("Dispatcher"));

// POST create shipment (Dispatcher only)
api.MapPost("/", async (ApplicationDbContext db, CreateShipmentRequest request) =>
{
    var shipment = new Shipment
    {
        TrackingNumber = GenerateTrackingNumber(),
        Origin = request.Origin,
        Destination = request.Destination,
        CustomerEmail = request.CustomerEmail,
        EstimatedDelivery = request.EstimatedDelivery,
        CreatedAt = DateTime.UtcNow,
        Status = "Pending"
    };
    db.Shipments.Add(shipment);
    await db.SaveChangesAsync();
    return Results.Created($"/api/shipments/{shipment.Id}", new ShipmentDto
    {
        Id = shipment.Id,
        TrackingNumber = shipment.TrackingNumber,
        Origin = shipment.Origin,
        Destination = shipment.Destination,
        Status = ShipmentStatus.Pending,
        CreatedAt = shipment.CreatedAt,
        EstimatedDelivery = shipment.EstimatedDelivery,
        CustomerEmail = shipment.CustomerEmail,
        Notes = shipment.Notes
    });
}).RequireAuthorization(p => p.RequireRole("Dispatcher"));

// PUT update shipment status (Dispatcher only)
api.MapPut("/{id}/status", async (ApplicationDbContext db, int id, UpdateShipmentStatusRequest request) =>
{
    var shipment = await db.Shipments.FindAsync(id);
    if (shipment is null) return Results.NotFound();

    shipment.Status = request.Status.ToString();
    shipment.Notes = request.Notes ?? shipment.Notes;
    await db.SaveChangesAsync();

    return Results.Ok(new ShipmentDto
    {
        Id = shipment.Id,
        TrackingNumber = shipment.TrackingNumber,
        Origin = shipment.Origin,
        Destination = shipment.Destination,
        Status = Enum.Parse<ShipmentStatus>(shipment.Status),
        CreatedAt = shipment.CreatedAt,
        EstimatedDelivery = shipment.EstimatedDelivery,
        CustomerEmail = shipment.CustomerEmail,
        Notes = shipment.Notes
    });
}).RequireAuthorization(p => p.RequireRole("Dispatcher"));

// GET track by tracking number (any authenticated user)
api.MapGet("/track/{trackingNumber}", async (ApplicationDbContext db, string trackingNumber) =>
{
    var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    if (shipment is null) return Results.NotFound();

    return Results.Ok(new ShipmentDto
    {
        Id = shipment.Id,
        TrackingNumber = shipment.TrackingNumber,
        Origin = shipment.Origin,
        Destination = shipment.Destination,
        Status = Enum.Parse<ShipmentStatus>(shipment.Status),
        CreatedAt = shipment.CreatedAt,
        EstimatedDelivery = shipment.EstimatedDelivery,
        CustomerEmail = shipment.CustomerEmail,
        Notes = shipment.Notes
    });
}).RequireAuthorization();

// GET my shipments (authenticated user, matched by email)
api.MapGet("/my", async (ApplicationDbContext db, ClaimsPrincipal user) =>
{
    var email = user.FindFirstValue(ClaimTypes.Email) ?? user.FindFirstValue(ClaimTypes.Name);
    if (string.IsNullOrEmpty(email)) return Results.Ok(Array.Empty<ShipmentDto>());

    var shipments = await db.Shipments
        .Where(s => s.CustomerEmail == email)
        .OrderByDescending(s => s.CreatedAt)
        .ToListAsync();

    return Results.Ok(shipments.Select(s => new ShipmentDto
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = Enum.Parse<ShipmentStatus>(s.Status),
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    }));
}).RequireAuthorization();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

app.Run();

