@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>📦 Dispatcher Dashboard</h2>

<div class="mb-3 d-flex gap-3 align-items-end">
    <div>
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <button class="btn btn-primary" @onclick="ToggleCreateForm">
        @(showCreateForm ? "Cancel" : "+ New Shipment")
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Origin</label>
                    <input class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Destination</label>
                    <input class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Customer Email</label>
                    <input class="form-control" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Est. Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
            </div>
            <button class="btn btn-success mt-2" @onclick="CreateShipment">Create</button>
        </div>
    </div>
}

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

@if (shipments is null)
{
    <p>Loading...</p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in shipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>
                        @if (editingId == s.Id)
                        {
                            <select class="form-select form-select-sm" @bind="editStatus">
                                @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@st">@st</option>
                                }
                            </select>
                        }
                        else
                        {
                            <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                        }
                    </td>
                    <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>@s.CustomerEmail</td>
                    <td>
                        @if (editingId == s.Id)
                        {
                            <button class="btn btn-sm btn-success" @onclick="() => SaveStatus(s.Id)">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="() => editingId = null">Cancel</button>
                        }
                        else
                        {
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(s)">Edit</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private bool showCreateForm;
    private CreateShipmentRequest newShipment = new();
    private int? editingId;
    private ShipmentStatus editStatus;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            var url = string.IsNullOrEmpty(statusFilter) ? "/api/shipments" : $"/api/shipments?status={statusFilter}";
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>(url);
            errorMessage = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private void ToggleCreateForm() => showCreateForm = !showCreateForm;

    private async Task CreateShipment()
    {
        try
        {
            var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
            if (response.IsSuccessStatusCode)
            {
                newShipment = new();
                showCreateForm = false;
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to create shipment.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private void StartEdit(ShipmentDto shipment)
    {
        editingId = shipment.Id;
        editStatus = shipment.Status;
    }

    private async Task SaveStatus(int id)
    {
        try
        {
            var request = new UpdateShipmentStatusRequest { Status = editStatus };
            var response = await Http.PutAsJsonAsync($"/api/shipments/{id}/status", request);
            if (response.IsSuccessStatusCode)
            {
                editingId = null;
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to update status.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h2>🔍 Track a Shipment</h2>

<div class="mb-4">
    <div class="input-group" style="max-width: 500px;">
        <input class="form-control" placeholder="Enter tracking number (e.g. SHP-DEMO0001)"
               @bind="trackingNumber" @onkeydown="HandleKeyDown" />
        <button class="btn btn-primary" @onclick="SearchShipment">Track</button>
    </div>
</div>

@if (searching)
{
    <p>Searching...</p>
}
else if (searchError is not null)
{
    <div class="alert alert-warning">@searchError</div>
}
else if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <strong>@trackedShipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <div class="row mb-3">
                <div class="col-md-6">
                    <p><strong>Origin:</strong> @trackedShipment.Origin</p>
                    <p><strong>Destination:</strong> @trackedShipment.Destination</p>
                    <p><strong>Created:</strong> @trackedShipment.CreatedAt.ToString("MMM dd, yyyy")</p>
                    @if (trackedShipment.EstimatedDelivery.HasValue)
                    {
                        <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</p>
                    }
                    @if (!string.IsNullOrEmpty(trackedShipment.Notes))
                    {
                        <p><strong>Notes:</strong> @trackedShipment.Notes</p>
                    }
                </div>
                <div class="col-md-6">
                    <h5>Status: <span class="badge @GetStatusBadge(trackedShipment.Status) fs-6">@trackedShipment.Status</span></h5>
                    <div class="mt-3">
                        @{
                            var steps = new[] { ShipmentStatus.Pending, ShipmentStatus.PickedUp, ShipmentStatus.InTransit, ShipmentStatus.OutForDelivery, ShipmentStatus.Delivered };
                            var currentIndex = Array.IndexOf(steps, trackedShipment.Status);
                            var isCancelled = trackedShipment.Status == ShipmentStatus.Cancelled;
                        }
                        @if (isCancelled)
                        {
                            <div class="alert alert-danger">This shipment has been cancelled.</div>
                        }
                        else
                        {
                            <div class="progress" style="height: 25px;">
                                @{
                                    var pct = currentIndex >= 0 ? (int)((currentIndex + 1) * 100.0 / steps.Length) : 0;
                                }
                                <div class="progress-bar bg-success" role="progressbar"
                                     style="width: @(pct)%">
                                    @trackedShipment.Status
                                </div>
                            </div>
                        }
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr />
<h3>📋 My Shipments</h3>

@if (myShipments is null)
{
    <p>Loading your shipments...</p>
}
else if (!myShipments.Any())
{
    <p class="text-muted">No shipments associated with your account.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in myShipments)
            {
                <tr style="cursor: pointer" @onclick="() => TrackFromList(s.TrackingNumber)">
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@s.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string trackingNumber = "";
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;
    private bool searching;
    private string? searchError;

    protected override async Task OnInitializedAsync()
    {
        await LoadMyShipments();
    }

    private async Task LoadMyShipments()
    {
        try
        {
            myShipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/my");
        }
        catch
        {
            myShipments = new();
        }
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        searchError = null;
        trackedShipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{trackingNumber.Trim()}");
            if (response.IsSuccessStatusCode)
            {
                trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                searchError = "Shipment not found. Please check the tracking number.";
            }
        }
        catch (Exception ex)
        {
            searchError = $"Error searching: {ex.Message}";
        }
        finally
        {
            searching = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchShipment();
        }
    }

    private async Task TrackFromList(string tn)
    {
        trackingNumber = tn;
        await SearchShipment();
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

