128.     private int? editingId;
129.     private ShipmentStatus editStatus;
130.     private string? errorMessage;
131. 
132.     protected override async Task OnInitializedAsync()
133.     {
134.         await LoadShipments();
135.     }
136. 
137.     private async Task LoadShipments()
138.     {
139.         try
140.         {
141.             var url = string.IsNullOrEmpty(statusFilter) ? "/api/shipments" : $"/api/shipments?status={statusFilter}";
142.             shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>(url);
143.             errorMessage = null;
144.         }
145.         catch (Exception ex)
146.         {
147.             errorMessage = $"Failed to load shipments: {ex.Message}";
148.         }
149.     }
150. 
151.     private void ToggleCreateForm() => showCreateForm = !showCreateForm;
152. 
153.     private async Task CreateShipment()
154.     {
155.         try
156.         {
157.             var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
158.             if (response.IsSuccessStatusCode)
159.             {
160.                 newShipment = new();
161.                 showCreateForm = false;
162.                 await LoadShipments();
163.             }
164.             else
165.             {
166.                 errorMessage = "Failed to create shipment.";
167.             }
168.         }
169.         catch (Exception ex)
170.         {
171.             errorMessage = $"Error: {ex.Message}";
172.         }
173.     }
174. 
175.     private void StartEdit(ShipmentDto shipment)
176.     {
177.         editingId = shipment.Id;
178.         editStatus = shipment.Status;
179.     }
180. 
181.     private async Task SaveStatus(int id)
182.     {
183.         try
184.         {
185.             var request = new UpdateShipmentStatusRequest { Status = editStatus };
186.             var response = await Http.PutAsJsonAsync($"/api/shipments/{id}/status", request);
187.             if (response.IsSuccessStatusCode)
188.             {
189.                 editingId = null;
190.                 await LoadShipments();
191.             }
192.             else
193.             {
194.                 errorMessage = "Failed to update status.";
195.             }
196.         }
197.         catch (Exception ex)
198.         {
199.             errorMessage = $"Error: {ex.Message}";
200.         }
201.     }
